var b="url",c="任务出库.html",d="generationDate",e=new Date(1781590697381.11),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="axhubclickvalue",s="page",t="packageId",u="828e468265664640a75a3eff70e9af67",v="type",w="Axure:Page",x="任务出库",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="6e499f3dcfb943cdb6ebb0c3e4f81d7b",E="label",F="确定",G="说明",H="<p><span>1.按</span><span style=\"text-decoration:underline ;\">编辑域</span><span>内文本覆盖</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.若当前</span><span style=\"text-decoration:underline ;\">编辑域</span><span>为空，将对应&quot;备注&quot;的文本置为'添加'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.若当前</span><span style=\"text-decoration:underline ;\">编辑域</span><span>非空，将对应&quot;备注&quot;的文本置为'已填写'</span></p><p><span>2.关闭当前弹窗</span></p><p><span>3.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">返回Toast提示：</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#7F7F7F;\">操作成功</span></p>",I="2",J="1406616e5a05444cbf5589eb952f0f77",K="保存",L="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.校验&quot;本次出库&quot;非空且数值大于0，否则Toast提示：请输入当前批次本次出库数量</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.校验&quot;</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">本次出库≤批次库存</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&quot;，否则Toast提示：出库数量不得超出库存数量</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">3.通过全部校验</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; a.根据当前'散装批次码'是否存在于扫码明细中进行添加/修改</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a1.不存在</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.将'散装批次码'补充至当前扫码清单的【明细】中</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.补充位置：以详情页逻辑为准，按'散装批次码'顺序</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a2.存在</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.更新原有的&quot;本次出库&quot;值</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; b.将'散装批次码'对应的&quot;款号&quot;的清单组信息更新</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b1.更新该款式组中该“颜色+尺码”对应的“本次出库”清单</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b1.更新该款式组的“批次”、“数量”合计值</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; c.关闭当前弹窗</span></p>",M="3",N="1c3452aa434a4882930fbbd68b6be227",O="<p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#02A7F0;\">校验逻辑</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.再次校验扫码明细清单中“散装批次码”于[成品管理系统&gt;&gt;成品仓库：成品库存]的</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">散装库存</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">中的'件数'均大于当前填写的&quot;本次出库&quot;，否则Toast提示：库存变更，出库数量超出当前库存(</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0000FF;\">款号</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0000FF;\">散装批次码</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; a.例：出库数量超出当前库存(Q250601：X9FHULTZT5)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.跟随</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">配置项</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">判断，当[ </span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#7B4D12;\">system_config_limit_on_out == 0</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"> ]校验全部款式下&quot;待出库数≥本次出库&quot;，否则Toast提示：出库数量超出要求出库数量(</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0000FF;\">款号</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0000FF;\">颜色</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0000FF;\">尺码</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; a.例：出库数量超出当前库存(Q250601：黑色：S)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"><br></span></p><p><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#02A7F0;\">执行逻辑</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">1.按当前扫码明细“散装批次码”包含的</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">库位所属'仓库'</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#D9001B;\">去重</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">后对应条数的“出库单”至[成品管理系统&gt;&gt;成品仓库：出库单]中</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; a.成品出库单：CPO-6位当前年月日-2位流水递增</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a1.例：CPO-250418-67</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; b.出库类型：跟随当前</span><span style=\"font-family:'Arial Cursiva', 'Arial Normal', 'Arial', sans-serif;font-style:italic;\">散装出库任务</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"> 的&quot;来源&quot;</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b1.来源==生产下发：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#A30014;\">生产出库[任务]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b2.来源==直接申请：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#A30014;\">申请出库[任务]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; c.出库方式：散装</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; d.客户：跟随当前</span><span style=\"font-family:'Arial Cursiva', 'Arial Normal', 'Arial', sans-serif;font-style:italic;\">散装出库任务</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"> 的&quot;客户&quot;</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; e.关联单据：跟随当前</span><span style=\"font-family:'Arial Cursiva', 'Arial Normal', 'Arial', sans-serif;font-style:italic;\">散装出库任务</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"> 的&quot;生产订单&quot;</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; f.款号：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#4B7902;\">汇总</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">该</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">去重依据</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">对应的“散装批次码”上的</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#4B7902;\">'款号'后去重</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">拼接</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; g.出库仓库：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">去重依据</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">对应的“出库仓库”</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; h.批次：取该</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">去重依据</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">对应的</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#4B7902;\">“散装批次码”个数</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; i.件数：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#4B7902;\">合计</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">该</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">去重依据</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">对应的“散装批次码”的</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#4B7902;\">'本次出库'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; j.备注：以当前弹窗中的&quot;出库备注编辑域&quot;为准</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; k.创建时间、创建人：以当前时间及账号赋值</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; l.</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">[子表1]</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">出库汇总</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">：按出库单的</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">去重依据</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">关联的“散装批次码”上的'款号+颜色+尺码'再去重</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; </span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#6300BF;\">(暂时不用开发出库单详情页，字段样式可参考出库单的【打印】)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; l1.款号：跟随当前再去重的'款号'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; l2.款名：跟随当前再去重的'款名'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; l3.颜色：跟随当前再去重的'颜色'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; l4.尺码：跟随当前再去重的'尺码'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; l5.出库件数：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#4B7902;\">合计</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">去重后</span><span style=\"font-family:'Arial Cursiva', 'Arial Normal', 'Arial', sans-serif;font-style:italic;\">相关散装批次码 </span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">于明细中的'</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#4B7902;\">本次出库</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; l6.单位：跟随当前再去重的'款式单位'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; l7.备注：取再去重的&quot;款号+颜色+尺码&quot;对应行的'备注'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; m.</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">[子表2]</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">出库明细</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">：按出库单的</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">去重依据</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">关联的“散装批次码”进行存储</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; </span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#6300BF;\">(暂时不用开发出库单详情页，其它字段不作描述)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; m1.箱标签/散装批次：取该'散装批次码'编号</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">2.按当前扫码明细中的</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;color:#02A7F0;\">“散装批次码”</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">个数</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">对应生成记录至[成品管理系统&gt;&gt;成品仓库：出入库日志]下</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">明细日志</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">中</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; a.箱标签/散装批次：以'散装批次码'进行赋值</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; b.方式：散装</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; c.类型：跟随当前</span><span style=\"font-family:'Arial Cursiva', 'Arial Normal', 'Arial', sans-serif;font-style:italic;\">散装出库任务</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"> 的&quot;来源&quot;</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; c1.来源==生产下发：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#A30014;\">生产出库[任务]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; c2.来源==直接申请：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#A30014;\">申请出库[任务]</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; d.款号、款名、颜色、尺码：取'散装批次码'于[成品管理系统&gt;&gt;成品仓库：散装批次标签]中对应的同名字段</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; e.单位：查询“款号”对应于[基础数据系统&gt;&gt;款式管理：款式列表]中的&quot;单位&quot;</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; f.数量：取当前扫码明细中该散装批次码'对应的</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#4B7902;\">'本次出库'</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#A30014;\">注意取负数</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; g.销售单价：当前“散装出库任务单(CPSC)”于[成品管理系统&gt;&gt;成品仓库：散装出库任务]中该&quot;款号+颜色+尺码&quot;对应行的'销售单价'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; h.客户：取当前&quot;散装出库任务单(CPSC)&quot;对应的'客户'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; i.关联生产单：当前</span><span style=\"font-family:'Arial Cursiva', 'Arial Normal', 'Arial', sans-serif;font-style:italic;\">散装出库任务</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"> 的&quot;生产订单&quot;</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; j.关联任务：当前&quot;散装出库任务单(CPSC)&quot;</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; k.任务创建人：当前“散装出库任务单(CPSC)”于[成品管理系统&gt;&gt;成品仓库：散装出库任务]对应的“创建人”</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; l.操作单据：取该散装批次码对应在</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#7B4D12;\">执行1</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">中生成的&quot;出库单&quot;的成品出库单号(CPO)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; m.操作时间、操作人：以当前时间及账号赋值</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">3.根据本次</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">扫码散装批次码</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">于[成品管理系统&gt;&gt;成品仓库：成品库存]的</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">散装库存</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">中的'件数'和</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#4B7902;\">'本次出库'</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">差值，依次</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#D9001B;\">更新/移除</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; a.件数(批次库存) &gt; 本次出库：视为更新</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a1.件数：以该'散装批次码'当前于[成品管理系统&gt;&gt;成品仓库：成品库存]中</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">散装库存</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">下的</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">'件数'</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#D9001B;\">减去</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">当前扫码明细中该'散装批次码'对应的</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">'本次出库'</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">为准</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.即 </span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">更新'件数'=原'件数'</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#D9001B;\">-</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">当前操作'本次出库'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a2.其它字段不作更新</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; b.件数(批次库存) = 本次出库：视为移除</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">4.当配置项 [ </span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#7B4D12;\">system_config_pms_outtask_auto_closed == 0</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\"> ] 时，查询散装出库任务(CPSC)在[成品管理系统&gt;&gt;成品仓库：散装出库任务]对应的&quot;出库进度&quot;数值</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; a.出库进度 &lt; 1：不做处理</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; b.出库进度 ≥ 1：将该出库任务的&quot;状态&quot;置为'已关闭'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">5.关闭弹窗，返回Toast提示：</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#7F7F7F;\">操作成功</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">6.页面跳转至</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;text-decoration:underline ;\">主页</span></p>",P="style",Q="baseStyle",R="627587b6038d43cca051c114ac41ad32",S="pageAlignment",T="center",U="fill",V="fillType",W="solid",X="color",Y=0xFFFFFFFF,Z="image",ba="imageAlignment",bb="near",bc="imageRepeat",bd="auto",be="favicon",bf="sketchFactor",bg="0",bh="colorStyle",bi="appliedColor",bj="fontName",bk="Applied Font",bl="borderWidth",bm="borderVisibility",bn="borderFill",bo=0xFF797979,bp="cornerRadius",bq="cornerVisibility",br="outerShadow",bs="on",bt=false,bu="offsetX",bv=5,bw="offsetY",bx="blurRadius",by="spread",bz="r",bA=0,bB="g",bC="b",bD="a",bE=0.349019607843137,bF="adaptiveStyles",bG="interactionMap",bH="diagram",bI="objects",bJ="id",bK="85d1b59496864b55aad336da16ed5d34",bL="friendlyType",bM="矩形",bN="vectorShape",bO="styleType",bP="visible",bQ=true,bR=810,bS=800,bT="0754c62993f2462f8c963e5373cbdfec",bU=0x1CFACD91,bV="location",bW="x",bX=2150,bY="y",bZ="imageOverrides",ca="generateCompound",cb="dc4ff3f8c63246889db9af3d25490c58",cc=1310,cd=0x1CCAF982,ce="c56baa6ea36642c39569081137e80cde",cf="手持终端",cg="referenceDiagramObject",ch=450,ci=1230,cj="masterId",ck="4fac3643f4954cc4b8de2be8db632c44",cl="53bb4c4d047e47d7a78c384fb636c7d6",cm="文本框",cn="textBox",co=410,cp=32,cq="stateStyles",cr="hint",cs="248f9d99051b4747b85c1a9f3bdba063",ct="disabled",cu="974bcd087d5142f3bfc6f4be1a16e4b3",c